patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index d4a2fe5e37ef..4326520139d0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -816,19 +816,24 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
     }

     Constant *C;
-    if (match(Src, m_OneUse(m_LShr(m_Value(X), m_ImmConstant(C))))) {
-      // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0
+    if (match(Src, m_LShr(m_Value(X), m_ImmConstant(C)))) {
+      // trunc (lshr X, C) to i1 --> icmp slt X, 0  if C == SrcWidth - 1
+      // trunc (lshr X, C) to i1 --> icmp ne (and X, C'), 0  otherwise
+      if (cast<ConstantInt>(C)->getZExtValue() == SrcWidth - 1)
+        return new ICmpInst(ICmpInst::ICMP_SLT, X, Zero);
       Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
       Value *MaskC = Builder.CreateShl(One, C);
       Value *And = Builder.CreateAnd(X, MaskC);
       return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
     }
-    if (match(Src, m_OneUse(m_c_Or(m_LShr(m_Value(X), m_ImmConstant(C)),
-                                   m_Deferred(X))))) {
-      // trunc (or (lshr X, C), X) to i1 --> icmp ne (and X, C'), 0
+    if (match(Src, m_AShr(m_Value(X), m_ImmConstant(C)))) {
+      // trunc (ashr X, C) to i1 --> icmp slt X, 0  if C == SrcWidth - 1
+      // trunc (ashr X, C) to i1 --> icmp ne (and X, C'), 0  otherwise
+      if (cast<ConstantInt>(C)->getZExtValue() == SrcWidth - 1)
+        return new ICmpInst(ICmpInst::ICMP_SLT, X, Zero);
       Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
       Value *MaskC = Builder.CreateShl(One, C);
-      Value *And = Builder.CreateAnd(X, Builder.CreateOr(MaskC, One));
+      Value *And = Builder.CreateAnd(X, MaskC);
       return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
     }

